42	/// Run a command with retries, sleeping between attempts.
43	fn run_retry(
44	    cmd: &str,
45	    args: &[&str],
46	    cwd: &Path,
47	    retries: u32,
48	    delay_secs: u64,
49	    verbose: bool,
50	) -> Result<String, Box<dyn std::error::Error>> {
51	    let mut last_err = String::new();
52	    for attempt in 1..=retries {
53	        match run(cmd, args, cwd) {
54	            Ok(out) => {
55	                if attempt > 1 {
56	                    eprintln!("  succeeded after {attempt} attempts");
57	                }
58	                return Ok(out);
59	            }
60	            Err(e) => {
61	                last_err = e.to_string();
62	                if attempt < retries {
63	                    if verbose {
64	                        eprintln!("  attempt {attempt}/{retries} failed: {last_err}");
65	                    }
66	                    eprintln!("  retrying in {delay_secs}s...");
67	                    std::thread::sleep(std::time::Duration::from_secs(delay_secs));
68	                }
69	            }
70	        }
71	    }
72	    Err(format!("failed after {retries} attempts: {last_err}").into())
73	}
