148	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
149	    let parent_dir = match &args.dir {
150	        Some(d) => d.clone(),
151	        None => std::env::current_dir()?,
152	    };
153	    let project_dir = parent_dir.join(&args.name);
154	    let session_dir = project_dir.join(".claude");
155	
156	    // Preflight checks
157	    eprintln!("Preflight checks...");
158	
159	    // Check tools
160	    std::process::Command::new("gh")
161	        .arg("auth")
162	        .arg("status")
163	        .stdout(std::process::Stdio::null())
164	        .stderr(std::process::Stdio::null())
165	        .status()
166	        .map_err(|_| "gh is not installed")?
167	        .success()
168	        .then_some(())
169	        .ok_or("gh is not authenticated (run: gh auth login)")?;
170	
171	    std::process::Command::new("jj")
172	        .arg("--version")
173	        .stdout(std::process::Stdio::null())
174	        .status()
175	        .map_err(|_| "jj is not installed")?;
176	
177	    let owner = match &args.owner {
178	        Some(o) => o.clone(),
179	        None => gh_whoami()?,
180	    };
181	
182	    if project_dir.exists() {
183	        return Err(format!("'{}' already exists", project_dir.display()).into());
184	    }
185	
186	    let code_repo = format!("{owner}/{}", args.name);
187	    let session_repo = format!("{owner}/{}.claude", args.name);
188	
189	    if gh_repo_exists(&owner, &args.name)? {
190	        return Err(format!("GitHub repo '{code_repo}' already exists").into());
191	    }
192	    if gh_repo_exists(&owner, &format!("{}.claude", args.name))? {
193	        return Err(format!("GitHub repo '{session_repo}' already exists").into());
194	    }
195	
196	    let visibility = if args.private {
197	        "--private"
198	    } else {
199	        "--public"
200	    };
201	
202	    if args.dry_run {
203	        eprintln!("\nDry run — would execute:");
204	        eprintln!("  1. Create directories: {}", project_dir.display());
205	        eprintln!("  2. git init both repos, jj git init --colocate session repo");
206	        eprintln!("  3. Add .vc-config.toml and .gitignore to both");
207	        eprintln!("  4. jj commit .claude repo (ochid: /none placeholder)");
208	        eprintln!("  5. gh repo create {session_repo} {visibility}, push");
209	        eprintln!("  6. Clean .claude, git submodule add");
210	        eprintln!("  7. git add + git commit code repo with ochid + .gitmodules");
211	        eprintln!("  8. gh repo create {code_repo} {visibility}, git push");
212	        eprintln!("  9. jj git init --colocate code repo, set bookmark");
213	        eprintln!("  10. Fix .claude ochid via git commit --amend, force push");
214	        eprintln!("  11. jj git init --colocate session repo");
215	        eprintln!("  12. Create Claude Code symlink");
216	        return Ok(());
217	    }
218	
219	    // Step 1: Create directories
220	    eprintln!("\nCreating project directories...");
221	    std::fs::create_dir_all(&session_dir)?;
222	
223	    // Step 2: git init + jj init
224	    // Code repo: git only until the end (jj doesn't understand submodules)
225	    // Session repo: git + jj from the start (no submodule issues)
226	    eprintln!("\nInitializing repos...");
227	    run("git", &["init"], &project_dir)?;
228	    run("git", &["init"], &session_dir)?;
229	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
230	
231	    // Step 3: Write config files
232	    eprintln!("\nWriting config files...");
233	    std::fs::write(project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
234	    std::fs::write(project_dir.join(".gitignore"), GITIGNORE_CODE)?;
235	    std::fs::write(session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
236	    std::fs::write(session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
237	
238	    // Step 4: Commit .claude repo first (need its changeID for code repo ochid)
239	    eprintln!("\nCommitting session repo...");
240	    // Code repo has no jj yet, so no changeID — use "none" placeholder.
241	    // The ochid can be fixed later with fix-desc once jj is initialized.
242	    let session_commit_body = "Initial commit\n\nochid: /none";
243	    run("jj", &["commit", "-m", session_commit_body], &session_dir)?;
244	
245	    // Get the .claude repo's committed changeID for the code repo ochid
246	    // After jj commit, the committed revision is @-
247	    let session_chid_output = std::process::Command::new("jj")
248	        .args([
249	            "log",
250	            "-r",
251	            "@-",
252	            "--no-graph",
253	            "-T",
254	            "change_id",
255	            "--limit",
256	            "1",
257	        ])
258	        .current_dir(&session_dir)
259	        .output()?;
260	    let session_chid_full = String::from_utf8_lossy(&session_chid_output.stdout)
261	        .trim()
262	        .to_string();
263	    let session_chid = &session_chid_full[..session_chid_full.len().min(12)];
264	
265	    // Step 5: Create .claude GitHub repo and push
266	    eprintln!("\nCreating GitHub repo {session_repo}...");
267	    run(
268	        "gh",
269	        &["repo", "create", &session_repo, visibility],
270	        &project_dir,
271	    )?;
272	
273	    let session_url = format!("git@github.com:{session_repo}.git");
274	    run(
275	        "git",
276	        &["remote", "add", "origin", &session_url],
277	        &session_dir,
278	    )?;
279	    // Set the bookmark before pushing
280	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
281	    run_retry(
282	        "jj",
283	        &["git", "push", "--bookmark", "main"],
284	        &session_dir,
285	        args.push_retries,
286	        args.push_retry_delay,
287	        args.verbose,
288	    )?;
289	
290	    // Step 6: Clean .claude contents and add as submodule
291	    eprintln!("\nAdding .claude as submodule...");
292	    // Remove the .claude directory contents so git submodule add can work
293	    std::fs::remove_dir_all(&session_dir)?;
294	
295	    run(
296	        "git",
297	        &["submodule", "add", "--force", &session_url, ".claude"],
298	        &project_dir,
299	    )?;
300	
301	    // Step 7: Commit code repo using git (jj doesn't understand submodules)
302	    eprintln!("\nCommitting code repo...");
303	    let code_commit_body = format!("Initial commit\n\nochid: /.claude/{session_chid}");
304	    run("git", &["add", "."], &project_dir)?;
305	    run("git", &["commit", "-m", &code_commit_body], &project_dir)?;
306	
307	    // Step 8: Create code GitHub repo and push
308	    eprintln!("\nCreating GitHub repo {code_repo}...");
309	    run(
310	        "gh",
311	        &["repo", "create", &code_repo, visibility],
312	        &project_dir,
313	    )?;
314	
315	    let code_url = format!("git@github.com:{code_repo}.git");
316	    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
317	    run_retry(
318	        "git",
319	        &["push", "origin", "main"],
320	        &project_dir,
321	        args.push_retries,
322	        args.push_retry_delay,
323	        args.verbose,
324	    )?;
325	
326	    // Step 9: Init jj on code repo and get its changeID
327	    eprintln!("\nInitializing jj...");
328	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
329	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
330	
331	    // Step 10: Fix session repo ochid using pure git (before jj init to avoid divergence)
332	    eprintln!("\nFixing session repo ochid...");
333	    let code_chid_output = std::process::Command::new("jj")
334	        .args([
335	            "log",
336	            "-r",
337	            "@-",
338	            "--no-graph",
339	            "-T",
340	            "change_id",
341	            "--limit",
342	            "1",
343	        ])
344	        .current_dir(&project_dir)
345	        .output()?;
346	    let code_chid_full = String::from_utf8_lossy(&code_chid_output.stdout)
347	        .trim()
348	        .to_string();
349	    let code_chid = &code_chid_full[..code_chid_full.len().min(12)];
350	    let fixed_session_body = format!("Initial commit\n\nochid: /{code_chid}");
351	    // Use git commit --amend before jj init so jj only ever sees one version
352	    run(
353	        "git",
354	        &["commit", "--amend", "-m", &fixed_session_body],
355	        &session_dir,
356	    )?;
357	    run("git", &["push", "--force", "origin", "main"], &session_dir)?;
358	
359	    // Now init jj on the session repo (clean state, no divergence)
360	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
361	
362	    // Step 12: Create Claude Code symlink
363	    eprintln!("\nCreating Claude Code symlink...");
364	    let symlink_dir = {
365	        let home =
366	            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
367	        PathBuf::from(home).join(".claude").join("projects")
368	    };
369	
370	    let meta = symlink::probe_symlink(
371	        &symlink_dir.join(symlink::encode_path(
372	            project_dir
373	                .to_str()
374	                .ok_or("project path is not valid UTF-8")?,
375	        )),
376	    );
377	    let plan = symlink::compute_plan(&project_dir, Path::new(".claude"), &symlink_dir, meta)?;
378	    symlink::execute_plan(&plan, false)?;
379	    eprintln!(
380	        "  Symlink: {} -> {}",
381	        plan.symlink_path.display(),
382	        plan.abs_target.display()
383	    );
384	
385	    eprintln!("\nDone! Project created at {}", project_dir.display());
386	    eprintln!("  Code repo:    {code_repo}");
387	    eprintln!("  Session repo: {session_repo}");
388	
389	    Ok(())
390	}
