427	/// Parse and evaluate a revset string, returning commit IDs.
428	pub fn resolve_revset(
429	    workspace: &Workspace,
430	    repo: &Arc<ReadonlyRepo>,
431	    revset_str: &str,
432	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
433	    let aliases_map = RevsetAliasesMap::new();
434	    let fileset_aliases_map = FilesetAliasesMap::new();
435	    let extensions = RevsetExtensions::default();
436	    let workspace_root = workspace.workspace_root().to_path_buf();
437	    let path_converter = RepoPathUiConverter::Fs {
438	        cwd: workspace_root.clone(),
439	        base: workspace_root,
440	    };
441	    let workspace_name = workspace.workspace_name();
442	    let workspace_ctx = RevsetWorkspaceContext {
443	        path_converter: &path_converter,
444	        workspace_name,
445	    };
446	    let context = RevsetParseContext {
447	        aliases_map: &aliases_map,
448	        local_variables: HashMap::new(),
449	        user_email: "",
450	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
451	        default_ignored_remote: None,
452	        fileset_aliases_map: &fileset_aliases_map,
453	        use_glob_by_default: false,
454	        extensions: &extensions,
455	        workspace: Some(workspace_ctx),
456	    };
457	
458	    let mut diagnostics = RevsetDiagnostics::new();
459	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
460	
461	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
462	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
463	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
464	    let revset = resolved.evaluate(repo.as_ref())?;
465	
466	    let mut commit_ids = Vec::new();
467	    for result in revset.iter() {
468	        commit_ids.push(result?);
469	    }
470	    Ok(commit_ids)
471	}
