5	/// What action the symlink operation needs to take.
6	#[derive(Debug, PartialEq, Eq)]
7	pub enum SymlinkAction {
8	    /// Nothing exists at the symlink path — create it.
9	    Create,
10	    /// An existing symlink points somewhere else — caller must decide whether to replace.
11	    Replace { current_target: PathBuf },
12	    /// The symlink already points to the correct target — nothing to do.
13	    AlreadyCorrect,
14	}
