16	/// The result of planning a symlink operation.
17	#[derive(Debug)]
18	pub struct SymlinkPlan {
19	    /// Absolute path to the target directory (what the symlink points to).
20	    pub abs_target: PathBuf,
21	    /// Full path of the symlink to create/replace.
22	    pub symlink_path: PathBuf,
23	    /// What action is needed.
24	    pub action: SymlinkAction,
25	}
