27	/// Encode a path the way Claude Code does: replace `/` and `.` with `-`.
28	pub fn encode_path(path: &str) -> String {
29	    path.replace(['/', '.'], "-")
30	}
31	
32	/// Compute the symlink plan without performing any I/O.
33	///
34	/// # Arguments
35	/// * `cwd` — current working directory (used to derive the symlink name)
36	/// * `target` — the directory the symlink should point to (resolved to absolute)
37	/// * `symlink_dir` — parent directory for the symlink (e.g. `~/.claude/projects`)
38	/// * `target_exists` — whether the target directory exists on disk
39	/// * `symlink_meta` — what currently exists at the symlink path:
40	///   - `None` — nothing exists
41	///   - `Some(None)` — exists but is not a symlink (file or directory)
42	///   - `Some(Some(path))` — existing symlink pointing to `path`
43	pub fn compute_plan(
44	    cwd: &Path,
45	    target: &Path,
46	    symlink_dir: &Path,
47	    symlink_meta: Option<Option<PathBuf>>,
48	) -> Result<SymlinkPlan, String> {
49	    // Resolve target to absolute path
50	    let abs_target = if target.is_absolute() {
51	        target.to_path_buf()
52	    } else {
53	        cwd.join(target)
54	    };
55	
56	    // Derive symlink name from cwd
57	    let cwd_str = cwd
58	        .to_str()
59	        .ok_or_else(|| "current directory path is not valid UTF-8".to_string())?;
60	    let symlink_name = encode_path(cwd_str);
61	    let symlink_path = symlink_dir.join(symlink_name);
62	
63	    let action = match symlink_meta {
64	        None => SymlinkAction::Create,
65	        Some(None) => {
66	            return Err(format!(
67	                "'{}' exists and is not a symlink",
68	                symlink_path.display()
69	            ));
70	        }
71	        Some(Some(current_target)) => {
72	            if current_target == abs_target {
73	                SymlinkAction::AlreadyCorrect
74	            } else {
75	                SymlinkAction::Replace { current_target }
76	            }
77	        }
78	    };
79	
80	    Ok(SymlinkPlan {
81	        abs_target,
82	        symlink_path,
83	        action,
84	    })
85	}
