87	/// Read what exists at a path without following symlinks.
88	///
89	/// Returns:
90	/// - `None` — nothing exists
91	/// - `Some(None)` — exists but is not a symlink
92	/// - `Some(Some(target))` — symlink pointing to target
93	pub fn probe_symlink(path: &Path) -> Option<Option<PathBuf>> {
94	    match path.symlink_metadata() {
95	        Err(_) => None,
