        ]);
        assert_eq!(args.repo, "owner/repo");
        assert_eq!(args.dir, Some(PathBuf::from("/tmp/projects")));
        assert!(args.dry_run);
        assert!(args.verbose);
    }

    #[test]
    fn missing_repo() {
        let err = parse_err(&["vc-x1", "clone"]);
